import{_ as t,c as e,o,d as p}from"./app.4c449db1.js";var s="/assets/2-etazh.53bfd38e.png";const f='{"title":"\u041F\u0440\u043E\u043E\u0431\u0440\u0430\u0437 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","description":"","frontmatter":{"title":"\u041F\u0440\u043E\u043E\u0431\u0440\u0430\u0437 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439","subtitle":"\u0424\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0433\u043E \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0438\u0434\u0435\u0438 OOLEY","date":"2014-12-08","cover":"2-etazh-s.png"},"headers":[],"relativePath":"theory/system/proobraz-om/index.md"}',r={},_=p('<p>\u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0439 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u0446\u0435\u043D\u0442\u0440 \u043C\u043E\u0433 \u0431\u044B \u0441\u043E\u0431\u0440\u0430\u0442\u044C \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0448\u0438\u0440\u043E\u043A\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0438 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0441\u0430\u043C\u044B\u0445\xA0\u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u043B\u043E\u0449\u0430\u0434\u043E\u043A \u043C\u043E\u0436\u0435\u0442 \u0434\u0430\u0442\u044C \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u0443 \u0432\u044B\u0431\u043E\u0440\u0430 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0435 \u043B\u043E\u043A\u0430\u043B\u044C\u043D\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435, \u043F\u0443\u0441\u0442\u044C \u0438 \u043D\u0435 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0430\u043C\u0438 \u043F\u043E \u0441\u0435\u0431\u0435, \u043D\u043E \u0434\u043E\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0434\u0440\u0443\u0433 \u0434\u0440\u0443\u0433\u0430, \u043C\u043E\u0433\u0443\u0442 \u0441\u0442\u0430\u0442\u044C \u0443\u0437\u043B\u0430\u043C\u0438 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0441\u0435\u0442\u0438.</p><p>\u041F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u043C \u043F\u0440\u043E\u043E\u0431\u0440\u0430\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0442\u0430\u043A\u043E\u0433\u043E \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430, \xA0\u0447\u0442\u043E\u0431\u044B \u043E\u0431\u0441\u0443\u0434\u0438\u0442\u044C\xA0\u0435\u0433\u043E \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0438 \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u0435, \xA0\u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u0435\u0433\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C\xA0\u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u044B\u043C \u0438 \u043F\u0440\u043E\u0441\u0442\u044B\u043C, \u043D\u043E \u0432 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u044B\u043C \u0438 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u044B\u043C.</p><p><img src="'+s+'" alt=""></p><p>\u0414\u0432\u0430 \u0433\u0440\u043E\u043C\u043A\u0438\u0445 \u0438 \u0434\u0432\u0430 \u0442\u0438\u0445\u0438\u0445 \u0431\u043B\u043E\u043A\u0430, \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u044B\u0445 \u043B\u0435\u0441\u0442\u043D\u0438\u0446\u0430\u043C\u0438 \u0438 \u0431\u0430\u043B\u043A\u043E\u043D\u0430\u043C\u0438. \u0414\u0435\u043A\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u0438 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0435 \u043E\u0437\u0435\u043B\u0435\u043D\u0435\u043D\u0438\u0435. \u0412\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u0430\u0436\u0435 \u0441\u043E\u0431\u0440\u0430\u0442\u044C \u0442\u0430\u043A\u043E\u0435 \u0437\u0434\u0430\u043D\u0438\u0435 \u0438\u0437 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u043D\u044B\u0445 \u043C\u043E\u0440\u0441\u043A\u0438\u0445 \u043A\u043E\u043D\u0442\u0435\u0439\u043D\u0435\u0440\u043E\u0432.</p><p>\u042D\u0442\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043D\u044B\u0439 \u0438 \u0443\u043F\u0440\u043E\u0449\u0435\u043D\u043D\u044B\u0439 \u043F\u0440\u0438\u043C\u0435\u0440 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043C\u043E\u0436\u043D\u043E \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C \u0438\u0434\u0435\u0438 OOLEY \u0432 \u0432\u0438\u0434\u0435 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043C\u043E\u0434\u0443\u043B\u044C\u043D\u043E\u0433\u043E \u0437\u0434\u0430\u043D\u0438\u044F. \u0412 &quot;\u0433\u0440\u043E\u043C\u043A\u0438\u0445&quot; \u0437\u0430\u043B\u0430\u0445 \u043C\u043E\u0436\u043D\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u0441\u0442\u0430\u043D\u043A\u0438 \u0438 \u0434\u0440\u0443\u0433\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C, \u043C\u0435\u0442\u0430\u043B\u043B\u043E\u043C. \u041F\u0438\u043B\u0435\u043D\u0438\u0435, \u0441\u0432\u0435\u0440\u043B\u0435\u043D\u0438\u0435, \u0448\u043B\u0438\u0444\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u0444\u0440\u0435\u0437\u0435\u0440\u043E\u0432\u043A\u0430 \u2014 \u0448\u0443\u043C\u043D\u044B\u0435 \u0438 \u043F\u044B\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0438 \u0437\u0434\u0435\u0441\u044C \u043D\u0443\u0436\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0432 \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u0445 \u043E\u0447\u043A\u0430\u0445, \u0440\u0435\u0441\u043F\u0438\u0440\u0430\u0442\u043E\u0440\u0435 \u0438, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u043D\u0430\u0443\u0448\u043D\u0438\u043A\u0430\u0445. \u0422\u0438\u0445\u0438\u0435 \u043A\u043E\u043C\u043D\u0430\u0442\u044B \u043F\u043E\u0434\u043E\u0439\u0434\u0443\u0442 \u0434\u043B\u044F \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0440\u0438\u0441\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043A\u043B\u0435\u0438\u0432\u0430\u043D\u0438\u044F, \u043B\u0435\u043F\u043A\u0438, \u0448\u0438\u0442\u044C\u044F, \u0432\u044F\u0437\u0430\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0447\u0438\u0445 \u0437\u0430\u043D\u044F\u0442\u0438\u0439, \u0442\u0440\u0435\u0431\u0443\u044E\u0449\u0438\u0445 \u0442\u0438\u0448\u0438\u043D\u044B \u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438. \u0421\u0442\u0435\u043A\u043B\u044F\u043D\u043D\u044B\u0435 \u0444\u0430\u0441\u0430\u0434\u044B \u043D\u0435\u0441\u0443\u0442 \u0438\u0434\u0435\u044E \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0438 \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u043E\u0441\u0442\u0438 \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u043A \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044E. \u0417\u0435\u043B\u0435\u043D\u044B\u0435 \u043D\u0430\u0441\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0435 \u043A\u043E\u0437\u044B\u0440\u044C\u043A\u0438, \u0441\u043C\u043E\u0433\u0443\u0442 \u0434\u0430\u0442\u044C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u0443\u044E \u0437\u0430\u0449\u0438\u0442\u0443 \u043E\u0442 \u0438\u0437\u043B\u0438\u0448\u043D\u0435\u0433\u043E \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u043E\u0433\u043E \u0438\u0437\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0438 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u0441 \u043D\u0438\u043C \u043F\u0440\u043E\u0431\u043B\u0435\u043C. \u041E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0435 \u0432\u0445\u043E\u0434\u044B \u0432 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0431\u043B\u043E\u043A\u0438 \u0434\u0430\u044E\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043D\u0435 \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u0441\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u0439 \u043B\u044E\u0434\u0435\u0439 \u0438 \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0447\u0430\u0441\u0442\u043D\u043E\u0441\u0442\u0438 \u0438 \u043B\u0438\u0447\u043D\u043E\u0439 \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043A\u0430\u0436\u0434\u043E\u043C\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0443.</p><p>\u042D\u0442\u0430 \u043C\u043E\u0434\u0435\u043B\u044C \u2014 \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u043F\u0440\u043E\u043E\u0431\u0440\u0430\u0437 \u0438 \u043D\u0443\u0436\u043D\u043E \u0435\u0449\u0435 \u043C\u043D\u043E\u0433\u043E\u0435 \u043F\u0440\u043E\u0434\u0443\u043C\u0430\u0442\u044C \u0438 \u0443\u0447\u0435\u0441\u0442\u044C \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u0440\u0430\u0437 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0441\u0442\u0430\u043B \u043F\u043E\u043D\u044F\u0442\u043D\u044B\u043C \u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u043C\u044B\u043C \u0432 \u043F\u043E\u043B\u043D\u043E\u0439 \u043C\u0435\u0440\u0435. \u0417\u0434\u0435\u0441\u044C \u0435\u0449\u0435 \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u043C\u0435\u0441\u0442\u0430 \u0434\u043B\u044F \u043E\u0431\u0449\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u0443\u0440\u043E\u043A\u043E\u0432 \u0438 \u043B\u0435\u043A\u0446\u0438\u0439. \u0414\u0443\u0448 \u0438 \u0440\u0430\u0437\u0434\u0435\u0432\u0430\u043B\u043A\u0430, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0433\u0434\u0435-\u0442\u043E \u0437\u0434\u0435\u0441\u044C \u043F\u043E\u043C\u0435\u0441\u0442\u044F\u0442\u0441\u044F, \u043D\u043E \u0432\u043E\u0442 \u043C\u0435\u0441\u0442\u0430 \u0434\u043B\u044F \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0437\u0430\u043F\u0430\u0441\u0430 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u044F\u0432\u043D\u043E \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0442\u0430\u043A\u0430\u044F \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0441\u043C\u043E\u0436\u0435\u0442 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0438\u0442\u044C \u0437\u0430\u043F\u0440\u043E\u0441\u0430\u043C \u043B\u0438\u0448\u044C \u043E\u0434\u043D\u043E\u0433\u043E \u043A\u0432\u0430\u0440\u0442\u0430\u043B\u0430, \u0434\u0430 \u0438 \u0442\u043E \u043D\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E. \u041D\u043E \u0432\u0435\u0434\u044C \u044D\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0430\u0447\u0430\u043B\u043E!</p><p>\u041F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u044C\u0442\u0435 \u0441\u0435\u0431\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0443\u044E \u0441\u0435\u0442\u044C \u0442\u0430\u043A\u0438\u0445 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445, \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u043E\u0431\u043C\u0435\u043D\u0430 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0435\u0439, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438, \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C\u0438\xA0\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438. \u0412 \u0442\u0430\u043A\u043E\u0439 \u0441\u0440\u0435\u0434\u0435 \u0443 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F <strong>\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C \u0441\u0435\u0431\u044F \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435\xA0\u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0430, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B \u0438 \u0432\u044B\u0440\u0430\u0436\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u0435\u0431\u044F \u0447\u0435\u0440\u0435\u0437 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0434\u0440\u0443\u0433\u0438\u0445</strong>.</p><p>\u042D\u0442\u043E \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0432\u0430\u0436\u043D\u043E \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0438 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u043E\u0433\u043E \u043A\u0440\u0438\u0437\u0438\u0441\u0430, \u043A\u043E\u0433\u0434\u0430 \u043C\u043D\u043E\u0433\u0438\u0435 \u043B\u044E\u0434\u0438 \u0442\u0435\u0440\u044F\u044E\u0442 \u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432\u0438\u0435 \u0438 \u0443\u0432\u0435\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0441\u0435\u0431\u0435. \u0422\u043E\u043B\u044C\u043A\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0448\u0438\u0440\u043E\u0442\u044B \u0441\u0432\u043E\u0438\u0445 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439 \u043C\u043E\u0433\u0443\u0442 \u043F\u0440\u0438\u043D\u0435\u0441\u0442\u0438 \u043B\u044E\u0434\u044F\u043C \u0443\u0432\u0435\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0441\u0432\u043E\u0438\u0445 \u0441\u0438\u043B\u0430\u0445 \u0438 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u0443\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u0443 \u0440\u0430\u0441\u043F\u043E\u0440\u044F\u0436\u0435\u043D\u0438\u044F \u0438\u043C\u0438. \u0414\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xA0\u043A\u0430\u0436\u0434\u043E\u043C\u0443 \u0432\u0430\u0436\u043D\u043E \u043F\u043E\u043F\u0440\u043E\u0431\u043E\u0432\u0430\u0442\u044C\xA0\u0441\u0435\u0431\u044F \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0432\u0438\u0434\u043E\u0432 \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u043E, \u0447\u0442\u043E \u0443 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0435\u0441\u0442\u044C \u0442\u0430\u043B\u0430\u043D\u0442, \u043D\u043E \u0447\u0442\u043E \u0438\u0445 \u0443 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0446\u0435\u043B\u044B\u0439 \u0431\u0443\u043A\u0435\u0442! \u0418 \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0438\u043C\u0438 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0438 \u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043F\u043E\u0436\u0435\u043B\u0430\u0435\u0442. \u0410 \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u044D\u0442\u0443 \u0441\u0432\u043E\u0431\u043E\u0434\u0443 \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C, \xA0\u043D\u0443\u0436\u0435\u043D \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043C \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C.</p><p><strong>\u041C\u0430\u0441\u0442\u0435\u0440\u0430 \u0434\u0435\u043B\u0430\u044E\u0442 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435.</strong> <strong>\u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435 \u0434\u0435\u043B\u0430\u044E\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C\u0438.</strong></p><blockquote><p>\u041A\u043E\u043B\u043B\u0435\u0433\u0438. OOLEY \u2014 \u043E\u0442\u043A\u0440\u044B\u0442\u0430\u044F \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0430 \u0434\u043B\u044F \u0434\u0438\u0441\u043A\u0443\u0441\u0441\u0438\u0438, \u043E\u0431\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430. \u0417\u0434\u0435\u0441\u044C \u043C\u043E\u0436\u043D\u043E \u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u0441\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0438\u0434\u0435\u044F\u043C\u0438, \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0443\u0441\u0438\u043B\u0438\u044F \u0438 \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0442\u044C \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0432\u044B\u0440\u0430\u0436\u0430\u0442\u044C \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0430. \u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0439\u0442\u0435, \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0439\u0442\u0435, \u0437\u0430\u043C\u0435\u0447\u0430\u0439\u0442\u0435, \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0439\u0442\u0435, \u0434\u0435\u043B\u0438\u0442\u0435\u0441\u044C, \xA0\u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0439\u0442\u0435\xA0\u0438 \u0441\u043E\u043E\u0431\u0449\u0430\u0439\u0442\u0435. \u0410 \u0435\u0441\u043B\u0438 \u0432\u0430\u043C \u043D\u0435\u0447\u0435\u0433\u043E \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C, \u0442\u043E \u0445\u043E\u0442\u044F \u0431\u044B \u0440\u0430\u0441\u0441\u043A\u0430\u0436\u0438\u0442\u0435 \u043E\u0431 OOLEY \u0437\u043D\u0430\u043A\u043E\u043C\u044B\u043C \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u043E\u0440\u0430\u043C, \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0430\u043C, \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0430\u043C, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0442\u0435\u043C, \u043A\u0442\u043E \u043D\u0435 \u0437\u043D\u0430\u0435\u0442, \u0447\u0435\u043C \u0441\u0435\u0431\u044F \u0437\u0430\u043D\u044F\u0442\u044C. \u041D\u0430\u0432\u0435\u0440\u043D\u044F\u043A\u0430 \u0441\u0440\u0435\u0434\u0438 \u043D\u0438\u0445 \u043D\u0430\u0439\u0434\u0443\u0442\u0441\u044F \u043B\u044E\u0434\u0438, \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0432 \u044D\u0442\u043E\u043C \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u043C \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u043C \u043F\u0440\u043E\u0435\u043A\u0442\u0435.</p></blockquote>',10),a=[_];function n(c,i,d,l,g,m){return o(),e("div",null,a)}var h=t(r,[["render",n]]);export{f as __pageData,h as default};
